const clients = [
  { name: 'Alfa Construction Inc.', ghlKey: 'YOUR_GHL_KEY', email: 'info@alfapaintingcarpentry.com', site: 'https://www.alfapaintingcarpentry.com/' },
  { name: 'Wolfs Siding Inc', ghlKey: 'YOUR_GHL_KEY', email: 'info@wolfs-siding.com', site: 'https://wolfs-siding.com/' },
  { name: 'RS Development Group', ghlKey: 'YOUR_GHL_KEY', email: 'info@rs-developmentgroup.com', site: 'https://rs-developmentgroup.com/' },
  { name: 'Mass HVAC', ghlKey: 'YOUR_GHL_KEY', email: 'info@masshvac.net', site: 'https://masshvac.net/' },
  { name: 'Maia Construction Inc', ghlKey: 'YOUR_GHL_KEY', email: 'contact@maiaconstruction.com', site: 'https://maiaconstruction.com/' },
  { name: 'JH Painting Services', ghlKey: 'YOUR_GHL_KEY', email: 'contact@jhpaintingservices.com', site: 'https://jhpaintingservices.com/' },
  { name: 'Dorys Cleaning Services', ghlKey: 'YOUR_GHL_KEY', email: 'contact@doryscleaningservices.com', site: 'https://doryscleaningservices.com/' }
];

// TEST MODE
const TEST_MODE = true;
const TEST_EMAIL = 'galaxyinfomkt@gmail.com';
if (TEST_MODE) clients.forEach(c => { c.originalEmail = c.email; c.email = TEST_EMAIL; });

return clients.map(c => ({ json: c }));

const client = $('Client List').item.json;
const data = $json;
const allContacts = data.contacts || [];

// Filter ONLY last 30 days by dateAdded
const now = new Date();
const thirtyAgo = new Date(now.getTime() - 30*24*60*60*1000);
const thirtyAgoMs = thirtyAgo.getTime();

const contacts = allContacts.filter(c => {
  if (!c.dateAdded) return false;
  return new Date(c.dateAdded).getTime() >= thirtyAgoMs;
});

const sources = {};
contacts.forEach(c => { const s = c.source || c.tags?.[0] || 'Direct'; sources[s] = (sources[s]||0)+1; });
const topSources = Object.entries(sources).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([k,v])=>k+': '+v).join(', ') || 'Sem dados';

const period = thirtyAgo.toISOString().split('T')[0] + ' a ' + now.toISOString().split('T')[0];
const mesesPT = ['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
const monthName = mesesPT[now.getMonth()] + ' ' + now.getFullYear();

const prompt = "Você é um redator de relatórios de marketing da Galaxy IT & Marketing. Escreva um relatório mensal de desempenho para o cliente '" + client.name + "' EM PORTUGUÊS DO BRASIL.\n\nDADOS REAIS (últimos 30 dias — " + period + "):\n- Novos contatos/leads nos últimos 30 dias: " + contacts.length + "\n- Total de contatos na base (histórico): " + allContacts.length + "\n- Principais fontes de leads do mês: " + topSources + "\n- Site: " + client.site + "\n\nREGRAS:\n- Comece com 'Olá, time da " + client.name + "!'\n- Destaques do mês: 3-4 bullets com números específicos\n- Análise das fontes de leads: quais canais trouxeram mais leads, quais precisam de atenção\n- Uma recomendação específica e acionável\n- Termine com 'Abraços, Equipe Galaxy IT & Marketing'\n- Máximo 200 palavras, tom profissional mas amigável\n- IMPORTANTE: escreva tudo em português brasileiro, não em inglês\n- Use os NÚMEROS REAIS dos dados acima, não invente nada";

const body = {
  model: 'llama-3.3-70b-versatile',
  messages: [{ role: 'user', content: prompt }],
  max_tokens: 700,
  temperature: 0.7
};

return [{ json: {
  ...client,
  newContacts: contacts.length,
  totalContactsHistorical: allContacts.length,
  topSources,
  monthName,
  period,
  aiBody: JSON.stringify(body)
}}];
